var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"이대로 계속 전진해! 정상까지 가는 거다!","JPN":"このまま前進だ！　頂上まで登るんだ！","ENG":"Keep advancing like this! We're heading all the way to the summit!","TWN":"繼續前進！前往山頂！"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"헉... 헉...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"한동안 잠잠하다 싶었는데... 또 현기증이 도진 건가?","JPN":"しばらく落ち着いていたと思ったら、まためまいが……症状が再発したのか？","ENG":"It had been quiet for a while... Is the dizziness coming back again?","TWN":"這段時間本來以為好一點了……又開始頭暈了嗎？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아직...","JPN":"まだ……","ENG":"Not yet...","TWN":"不行……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"가야 할 길이 먼데...","JPN":"先が長いのに……","ENG":"I still have a long way to go...","TWN":"還有很長的路要走……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 아이의 얼굴... 어떻게 생겼었지?","JPN":"あの子の顔……どんなだったっけ？","ENG":"Her face... what did it look like again?","TWN":"那孩子的臉……長什麼樣子呢？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"왜 이렇게... 희미한 거야.","JPN":"なんでこんなに……ぼんやりとしか思い出せないんだ。","ENG":"Why is it so... blurry?","TWN":"為什麼會這麼……模糊呢。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"과학자! 정신 차려! 움직일 수 있겠나?!","JPN":"科学者！　しっかりしろ！　動けるか！？","ENG":"Hey! Stay with me! Can you move?!","TWN":"科學家！振作一點！你還能動嗎？！"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"으윽...","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"여기서 쓰러져있으면 죽어. 시체가 되어서도 영원히 이면세계에 남겨질 거라고.","JPN":"こんなところで倒れていたら死ぬぞ。死体になっても永遠に裏世界に残される。","ENG":"If you collapse here, you'll die. Even as a corpse, you'll be left behind in the Counterside forever.","TWN":"在這裡倒下的話就會死。就算變成屍體，也會永遠留在異界。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"난... 괜찮아.","JPN":"私は……大丈夫だ。","ENG":"I'm... fine.","TWN":"我……沒事。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"움직일 수 있... 어...","JPN":"動け……る……","ENG":"I can still... move...","TWN":"還能……動……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"이 주사들은... 이터니움 정제액? 설마 침식증후군인가?","JPN":"この注射は……エタニウム精製水？　まさか侵食症候群か？","ENG":"These syringes are... purified Eternium liquid? You have the Corruption Syndrome?","TWN":"這些針劑是……永恆之金晶體？難道是侵蝕症候群？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"당신 같은 중증 환자가 대체 왜 여기까지 온 거지?","JPN":"あんたみたいな重症患者がなぜここに来たんだ？","ENG":"Why would someone in such a severe condition come all the way here?","TWN":"像你這樣的重症患者，為什麼會來到這裡？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하아...","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정상에... 만나야 할 아이가 있어.","JPN":"頂上に……会わないといけない子がいるんだ。","ENG":"At the summit... there's a child I have to meet.","TWN":"在山頂……有我必須見到的孩子。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"반드시 집으로 데리러 오겠다고... 약속했으니까.","JPN":"必ず迎えに行くと……約束したから。","ENG":"I promised... I would come take her home.","TWN":"我曾經答應過她，一定會把她帶回家。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"그 아이 이름이 뭐지?","JPN":"その子の名前は？","ENG":"What's that child's name?","TWN":"那個孩子的名字是？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"...몰라.","JPN":"……分からない。","ENG":"...I don't know.","TWN":"……不知道。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"빌어먹을, 모르겠다고...!","JPN":"ちくしょう、分からないんだ……！","ENG":"Damn it, I can't remember...!","TWN":"該死，我不知道……！"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐... 하는 거야?","JPN":"何を……している？","ENG":"What... are you doing?","TWN":"你……在做什麼？"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"가자고, 내가 부축해서라도 정상까지 데려갈 테니까.","JPN":"行こう、俺の肩を貸してでも頂上まで連れていってやる。","ENG":"Come on. I'll help you up and get you to the summit if I have to carry you.","TWN":"走吧。就算我扶你，也要把你帶到山頂。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"...위험해.","JPN":"……危ない。","ENG":"...It's dangerous.","TWN":"……這樣很危險。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그러고 있다간... 당신까지 죽어...","JPN":"こんなことをしたら……あなたまで死ぬ……","ENG":"If you keep this up... you'll die too...","TWN":"再這樣下去……你也會死的……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"아내도 침식병이었어. 내 이름까지 잊을 정도로 병세가 심했지.","JPN":"妻も侵食病だったんだ。俺の名前も忘れるほどの重症だった。","ENG":"My wife had Corruption Syndrome too. It got so bad she even forgot my name.","TWN":"我的妻子也得了侵蝕病。她病得太嚴重，連自己的名字都忘了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"다 잊어도 되니까, 살아만 있어 달라고 했는데... 내 손길이 닿으니, 그 손을 꽉 잡더군.","JPN":"全部忘れてもいいから生きてくれと言ったら……触れた俺の手を、ぎゅっと握り返してくれたよ。","ENG":"I told her it was fine if she forgot everything, as long as she stayed alive... but when I reached out to her, she held my hand tight.","TWN":"就算全忘了，只要她能活著就好……當我握住她的手時，她卻緊緊握住了。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"그리곤 날 보며 웃어주지 않겠어? 그 온기와 감촉을 전부 기억하고 있는 것처럼.","JPN":"そして俺を見て笑ってくれたんだ。温もりと感触を全部覚えているみたいに。","ENG":"And then she smiled at me, like she still remembered all the warmth and feeling of it.","TWN":"然後她不是還對我笑了嗎？那份溫度與觸感我全都記得。"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"YOO_MI_NA_SPECIAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};